#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> rotateArray(vector<int>& nums) {
        if (!nums.empty()) {
            int temp = nums[0];
            for (int i = 0; i < nums.size() - 1; i++) {
                nums[i] = nums[i + 1];
            }
            nums.back() = temp;
        }
        return nums;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    vector<int> ans = sol.rotateArray(nums);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
